export default "import { Box, Button, Drawer, LinearProgress } from '@mui/material'\nimport { Suspense, useState } from 'react'\nimport { DrawerOptions } from './DrawerOptions'\n\nexport const DrawerRules = () => {\n  const [isDrawerOptions, setIsDrawerOptions] = useState(false)\n\n  const openDrawer = () => {\n    setIsDrawerOptions(true)\n  }\n\n  const closeDrawer = () => {\n    setIsDrawerOptions(false)\n  }\n\n  return (\n    <>\n      <Button onClick={openDrawer} >\n        Abrir drawer\n      </Button>\n      <Drawer\n        anchor='right'\n        open={isDrawerOptions}\n        onClose={closeDrawer}\n      >\n        <Box sx={{ width: '40rem' }}>\n          <Suspense fallback={<LinearProgress />}>\n            <DrawerOptions />\n          </Suspense>\n        </Box>\n      </Drawer>\n    </>\n  )\n}\n\n"